'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Question, UserAnswer } from '@/types';
import { submitPsychometric } from '../actions';
import { AlertCircle, CheckCircle2, ChevronRight, ChevronLeft, ActivitySquare, UserCircle, Target } from 'lucide-react';

interface PsychometricFlowProps {
  testId: string;
  questions: Question[];
}

export default function PsychometricFlow({ testId, questions }: PsychometricFlowProps) {
  const router = useRouter();
  
  const metaQuestions = questions.filter(q => q.type === 'meta');
  const psychometricQuestions = questions.filter(q => q.type === 'psychometric');

  const [testState, setTestState] = useState<'profile_setup' | 'meta_testing' | 'intro' | 'testing' | 'submitting'>('profile_setup');
  
  const [currentMetaIndex, setCurrentMetaIndex] = useState(0);
  const [currentPsychIndex, setCurrentPsychIndex] = useState(0);

  const [answers, setAnswers] = useState<UserAnswer[]>([]);
  const [profile, setProfile] = useState({ name: '', phone: '', age: '', grade: '' });

  const handleSelectOption = (questionId: string, optionId: string, isPsychTest: boolean) => {
    setAnswers(prev => [
      ...prev.filter(a => a.question_id !== questionId),
      { question_id: questionId, selected_option_id: optionId }
    ]);
    
    // Auto advance for smooth UX only in psychometric
    if (isPsychTest) {
      setTimeout(() => {
        if (currentPsychIndex < psychometricQuestions.length - 1) {
          setCurrentPsychIndex(currentPsychIndex + 1);
        }
      }, 400); 
    }
  };

  if (testState === 'profile_setup') {
    const isProfileComplete = profile.name.trim() && profile.phone.trim() && profile.age.trim() && profile.grade.trim();
    return (
      <div className="min-h-screen bg-white text-slate-800 flex flex-col pt-16 md:pt-24 px-6">
        <div className="max-w-3xl mx-auto w-full">
          <div className="bg-slate-50 border border-slate-200 px-8 py-6 rounded-3xl flex items-center justify-between mb-12 shadow-sm">
            <h1 className="text-xl md:text-2xl font-bold text-slate-900 flex items-center">
              <UserCircle className="w-6 h-6 mr-4 text-indigo-600" /> Candidate Profile
            </h1>
          </div>
          <div className="px-4">
            <h2 className="text-3xl md:text-5xl font-extrabold text-slate-900 mb-4 tracking-tight">Tell us about yourself</h2>
            <p className="text-lg md:text-xl text-slate-500 mb-10 leading-relaxed">
              Please provide your basic details to personalize your psychometric orientation.
            </p>
            <div className="space-y-8 mb-12">
              <div>
                <label className="block text-base md:text-lg font-bold text-slate-700 mb-3">Full Name</label>
                <input type="text" placeholder="John Doe" className="w-full text-lg border-2 border-slate-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-4 focus:ring-indigo-100 focus:border-indigo-500 transition-all shadow-sm bg-slate-50" value={profile.name} onChange={(e) => setProfile({ ...profile, name: e.target.value })} />
              </div>
              <div className="grid grid-cols-2 gap-5">
                <div>
                 <label className="block text-sm font-semibold text-slate-700 mb-1">Phone Number</label>
                 <input type="tel" placeholder="+1 234 567 8900" className="w-full border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500" value={profile.phone} onChange={(e) => setProfile({ ...profile, phone: e.target.value })} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Age</label>
                  <input type="number" placeholder="e.g. 16" className="w-full border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500" value={profile.age} onChange={(e) => setProfile({ ...profile, age: e.target.value })} />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Class / Grade</label>
                  <input type="text" placeholder="e.g. 11th Grade" className="w-full border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500" value={profile.grade} onChange={(e) => setProfile({ ...profile, grade: e.target.value })} />
                </div>
              </div>
            </div>
            <div className="flex flex-col items-start pt-10 border-t border-slate-100">
               <button
                 disabled={!isProfileComplete}
                 onClick={() => setTestState(metaQuestions.length > 0 ? 'meta_testing' : 'intro')}
                 className={`font-bold text-lg px-10 py-4 rounded-xl transition-all flex items-center ${isProfileComplete ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg shadow-indigo-500/30' : 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200'}`}
               >
                 Next Steps <ChevronRight className="ml-2 w-5 h-5" />
               </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----- RENDERING: Meta Profiling -----
  if (testState === 'meta_testing' && metaQuestions.length > 0) {
    const currentQ = metaQuestions[currentMetaIndex];
    const currentAns = answers.find(a => a.question_id === currentQ.id);
    const progress = (currentMetaIndex / metaQuestions.length) * 100;

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
        <div className="w-full h-2 bg-slate-200 shrink-0">
          <div className="h-full bg-slate-800 transition-all duration-700 ease-out" style={{ width: `${progress}%` }} />
        </div>
        <div className="flex-grow flex flex-col items-center justify-center p-6 md:p-12 w-full">
          <div className="w-full max-w-3xl mx-auto">
            <div className="text-sm font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center">
              <Target className="w-5 h-5 mr-3 text-slate-700" /> Career Trajectory Profiling
            </div>
            <h2 className="text-3xl md:text-5xl font-black text-slate-900 mb-10 tracking-tight">{currentQ.question_text}</h2>
            <div className="space-y-4 mb-10">
              {currentQ.options.map(option => {
                const isSelected = currentAns?.selected_option_id === option.id;
                return (
                  <button key={option.id} onClick={() => handleSelectOption(currentQ.id, option.id, false)} className={`w-full text-left p-5 md:p-6 rounded-2xl border-2 transition-all ${isSelected ? 'border-slate-800 bg-slate-800 text-white shadow-lg' : 'border-slate-300 hover:border-slate-800 bg-white text-slate-700'}`}>
                    <span className="text-lg md:text-xl font-bold">{option.text}</span>
                  </button>
                );
              })}
            </div>
            <div className="flex items-center justify-between">
               <button onClick={() => { if (currentMetaIndex > 0) setCurrentMetaIndex(currentMetaIndex - 1); else setTestState('profile_setup'); }} className="flex items-center px-6 py-3 rounded-xl font-bold text-lg text-slate-600 bg-white border-2 border-slate-200 shadow-sm"><ChevronLeft className="w-5 h-5 mr-2" /> Previous</button>
               <button disabled={!currentAns} onClick={() => { if (currentMetaIndex < metaQuestions.length - 1) setCurrentMetaIndex(currentMetaIndex + 1); else setTestState('intro'); }} className={`flex items-center px-8 py-3 rounded-xl font-bold text-lg transition-all ${!currentAns ? 'text-white bg-slate-300 cursor-not-allowed' : 'text-white bg-slate-900 shadow-md'}`}>Next <ChevronRight className="w-5 h-5 ml-2" /></button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ----- RENDERING: Intro & Rules -----
  if (testState === 'intro') {
    return (
      <div className="min-h-screen bg-white text-slate-800 flex flex-col pt-16 px-6">
        <div className="max-w-4xl mx-auto w-full">
          <div className="bg-indigo-50 border border-indigo-100 px-8 py-6 rounded-3xl flex items-center justify-between mb-12 shadow-sm">
            <h1 className="text-2xl font-bold text-indigo-900 flex items-center"><ActivitySquare className="w-6 h-6 mr-4 text-indigo-600" /> Psychometric Evaluation</h1>
          </div>
          <div className="px-4">
            <h2 className="text-4xl font-extrabold tracking-tight text-slate-900 mb-6">Before You Begin</h2>
            <p className="text-xl text-slate-600 mb-10 max-w-3xl">This module maps out your personality tendencies, intrinsic motivations, and natural working styles. There are no right or wrong answers.</p>
            <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 mb-8 flex items-start">
              <AlertCircle className="w-6 h-6 text-indigo-600 shrink-0 mr-4 mt-0.5" />
              <div>
                <ul className="space-y-3 text-slate-700 font-medium">
                  <li>• Choose the option that resonates most with your natural behavior.</li>
                  <li>• Go with your first instinct rather than overthinking.</li>
                  <li>• This section is not timed. Take the time you need to answer authentically.</li>
                </ul>
              </div>
            </div>
             <button onClick={() => setTestState('testing')} className="mt-6 bg-indigo-600 text-white font-bold text-lg px-10 py-4 rounded-xl shadow-lg shadow-indigo-500/20 hover:bg-indigo-700 transition-all flex items-center">Proceed to Matrix <ChevronRight className="ml-2 w-5 h-5" /></button>
          </div>
        </div>
      </div>
    );
  }

  if (testState === 'submitting') {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-8 text-center">
        <div className="w-24 h-24 border-8 border-slate-100 border-t-indigo-600 rounded-full animate-spin shadow-lg mb-12" />
        <h2 className="text-4xl font-black text-slate-900 mb-6">Processing Profile Array</h2>
      </div>
    );
  }

  // ----- RENDERING: Testing Flow -----
  const currentQ = psychometricQuestions[currentPsychIndex];
  const progress = (currentPsychIndex / psychometricQuestions.length) * 100;
  const currentAns = answers.find(a => a.question_id === currentQ?.id);

  return (
    <div className="min-h-screen bg-white flex flex-col selection:bg-indigo-100/50">
      <div className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-slate-200 px-6 py-5 flex items-center justify-between shadow-sm">
        <div className="bg-slate-900 text-white px-5 py-2 rounded-full text-sm font-black uppercase tracking-widest">Psychometric Module</div>
        <div className="text-lg font-medium text-slate-500">
          Question <span className="text-slate-900 font-bold ml-1">{currentPsychIndex + 1}</span> / {psychometricQuestions.length}
        </div>
      </div>
      <div className="w-full h-2 bg-slate-100"><div className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-700 ease-out" style={{ width: `${progress}%` }} /></div>
      <div className="flex-grow flex flex-col items-center justify-center p-6 md:p-12 w-full">
        <div className="w-full max-w-4xl mx-auto">
          <div className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center"><ActivitySquare className="w-5 h-5 mr-3 text-indigo-500" /> Behavioral Inquiry</div>
          <h2 className="text-4xl font-extrabold text-slate-900 mb-10 leading-[1.25] tracking-tight">{currentQ.question_text}</h2>
          <div className="space-y-4">
            {currentQ.options.map(o => {
              const isSelected = currentAns?.selected_option_id === o.id;
              return (
              <button key={o.id} onClick={() => handleSelectOption(currentQ.id, o.id, true)} className={`w-full text-left p-6 rounded-2xl border-2 transition-all flex justify-between ${isSelected ? 'border-indigo-500 bg-indigo-50 shadow-md text-indigo-900' : 'border-slate-200 hover:border-indigo-500 text-slate-700'}`}>
                <span className="text-xl font-medium">{o.text}</span>
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-indigo-500' : 'border-slate-300'}`}><div className={`w-2.5 h-2.5 rounded-full ${isSelected ? 'bg-indigo-500' : ''}`} /></div>
              </button>
            )})}
          </div>
          <div className="mt-10 flex items-center justify-between">
            <button onClick={() => { if (currentPsychIndex > 0) setCurrentPsychIndex(currentPsychIndex - 1); else setTestState('intro'); }} className="flex items-center px-6 py-3 rounded-xl font-bold text-lg border-2 border-slate-200 shadow-sm"><ChevronLeft className="w-5 h-5 mr-2" /> Previous</button>
            <button disabled={!currentAns} onClick={async () => { if (currentPsychIndex < psychometricQuestions.length - 1) setCurrentPsychIndex(currentPsychIndex + 1); else { setTestState('submitting'); await submitPsychometric(testId, answers, profile); router.push('/success'); } }} className={`flex items-center px-8 py-3 rounded-xl font-bold text-lg shadow-sm ${!currentAns ? 'bg-slate-300 text-white cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:shadow-lg'}`}>{currentPsychIndex === psychometricQuestions.length - 1 ? <>Submit <CheckCircle2 className="w-5 h-5 ml-2" /></> : <>Next <ChevronRight className="w-5 h-5 ml-2" /></>}</button>
          </div>
        </div>
      </div>
    </div>
  );
}
